SELECT *
FROM clothings
WHERE user_id = #{userId}
  AND is_deleted = 0

    AND category = #{request.category}


    AND primary_color = #{request.primaryColor}


    AND material = #{request.material}


    AND style_tags LIKE CONCAT('%', #{request.styleTag}, '%')


    AND occasion_tags LIKE CONCAT('%', #{request.occasionTag}, '%')


    AND season_tags LIKE CONCAT('%', #{request.seasonTag}, '%')


    AND (
        name LIKE CONCAT('%', #{request.keyword}, '%')
        OR category LIKE CONCAT('%', #{request.keyword}, '%')
        OR primary_color LIKE CONCAT('%', #{request.keyword}, '%')
        OR brand LIKE CONCAT('%', #{request.keyword}, '%')
    )


    AND frequency_level >= #{request.minFrequency}


    AND frequency_level <= #{request.maxFrequency}


    ORDER BY wear_count
    ORDER BY frequency_level
    ORDER BY created_at


    ASC
    DESC

LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM clothings
WHERE user_id = #{userId}
  AND is_deleted = 0

    AND category = #{request.category}


    AND primary_color = #{request.primaryColor}


    AND material = #{request.material}


    AND style_tags LIKE CONCAT('%', #{request.styleTag}, '%')


    AND occasion_tags LIKE CONCAT('%', #{request.occasionTag}, '%')


    AND season_tags LIKE CONCAT('%', #{request.seasonTag}, '%')


    AND (
        name LIKE CONCAT('%', #{request.keyword}, '%')
        OR category LIKE CONCAT('%', #{request.keyword}, '%')
        OR primary_color LIKE CONCAT('%', #{request.keyword}, '%')
        OR brand LIKE CONCAT('%', #{request.keyword}, '%')
    )


    AND frequency_level >= #{request.minFrequency}


    AND frequency_level <= #{request.maxFrequency}

SELECT c.id, c.user_id AS userId, c.name, c.category, c.sub_category AS subCategory, c.primary_color AS primaryColor, c.material, c.style_tags AS styleTags, c.image_url AS imageUrl, c.source_type AS sourceType, c.wear_count AS wearCount, c.frequency_level AS frequencyLevel, c.created_at AS createdAt, u.username AS ownerUsername, u.nickname AS ownerNickname, u.email AS ownerEmail FROM clothings c LEFT JOIN users u ON u.id = c.user_id WHERE c.is_deleted = 0
AND c.user_id = #{request.userId}
AND c.category = #{request.category}
AND c.primary_color = #{request.primaryColor}
AND c.source_type = #{request.sourceType}
AND ( c.name LIKE CONCAT('%', #{request.keyword}, '%') OR c.category LIKE CONCAT('%', #{request.keyword}, '%') OR c.primary_color LIKE CONCAT('%', #{request.keyword}, '%') OR c.brand LIKE CONCAT('%', #{request.keyword}, '%') )
AND ( u.username LIKE CONCAT('%', #{request.ownerKeyword}, '%') OR u.nickname LIKE CONCAT('%', #{request.ownerKeyword}, '%') OR u.email LIKE CONCAT('%', #{request.ownerKeyword}, '%') )
ORDER BY c.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM clothings c
LEFT JOIN users u ON u.id = c.user_id
WHERE c.is_deleted = 0

    AND c.user_id = #{request.userId}


    AND c.category = #{request.category}


    AND c.primary_color = #{request.primaryColor}


    AND c.source_type = #{request.sourceType}


    AND (
        c.name LIKE CONCAT('%', #{request.keyword}, '%')
        OR c.category LIKE CONCAT('%', #{request.keyword}, '%')
        OR c.primary_color LIKE CONCAT('%', #{request.keyword}, '%')
        OR c.brand LIKE CONCAT('%', #{request.keyword}, '%')
    )


    AND (
        u.username LIKE CONCAT('%', #{request.ownerKeyword}, '%')
        OR u.nickname LIKE CONCAT('%', #{request.ownerKeyword}, '%')
        OR u.email LIKE CONCAT('%', #{request.ownerKeyword}, '%')
    )

SELECT *
FROM clothings
WHERE user_id = #{userId}
  AND is_deleted = 0

    AND purchase_link = #{purchaseLink}


    AND source_order_id = #{sourceOrderId}


    AND image_url = #{imageUrl}

LIMIT 1
